scwin.acb_qryConKnd_onchange = function (info) {
    var value = acb_qryConKnd.getValue();

    if(value == "공급일자"){
        div_qryConKnd1.show("");
        div_qryConKnd2.hide("");
        div_qryConKnd3.hide("");
        div_qryConKnd4.hide("");

    }else if(value == "전표번호"){
        div_qryConKnd1.hide("");
        div_qryConKnd2.show("");
        div_qryConKnd3.hide("");
        div_qryConKnd4.hide("");

    }else if(value == "부가세번호"){
        div_qryConKnd1.hide("");
        div_qryConKnd2.hide("");
        div_qryConKnd3.show("");
        div_qryConKnd4.hide("");

    }else if(value == "BL넘버"){
        div_qryConKnd1.hide("");
        div_qryConKnd2.hide("");
        div_qryConKnd3.hide("");
        div_qryConKnd4.show("");
    }

};

